using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}, Props: {personInfo.Properties.Count}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): check-without-throwing ---

// With the default reflection resolver every type resolves, so use a
// source-gen context that only knows about Person to show a "miss".
var restricted = new JsonSerializerOptions { TypeInfoResolver = PersonContext.Default };

if (restricted.TryGetTypeInfo<Person>(out var info))
{
    Console.WriteLine($"TryGet Person  => found: {info!.Type.Name}");
}
else
{
    Console.WriteLine("TryGet Person  => NOT found");
}

if (restricted.TryGetTypeInfo<int[]>(out var arrInfo))
{
    Console.WriteLine($"TryGet int[]   => found: {arrInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGet int[]   => NOT found (no metadata for this type)");
}

// --- types ---

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class PersonContext : JsonSerializerContext;

